import{_ as r,c as d,o,a3 as e}from"./chunks/framework.CTM16EAR.js";const p=JSON.parse('{"title":"附录：术语对照表","description":"Activity、活动清单、Todo、Task 等中英文与层级关系的集中说明，便于对照文档与界面。","frontmatter":{"title":"附录：术语对照表","description":"Activity、活动清单、Todo、Task 等中英文与层级关系的集中说明，便于对照文档与界面。"},"headers":[],"relativePath":"guide/appendix/glossary.md","filePath":"guide/appendix/glossary.md","lastUpdated":1781162755000}'),a={name:"guide/appendix/glossary.md"};function n(s,t,i,l,c,g){return o(),d("div",null,t[0]||(t[0]=[e('<h1 id="附录-术语对照" tabindex="-1">附录：术语对照 <a class="header-anchor" href="#附录-术语对照" aria-label="Permalink to &quot;附录：术语对照&quot;">​</a></h1><h2 id="行动的生命周期" tabindex="-1">行动的生命周期 <a class="header-anchor" href="#行动的生命周期" aria-label="Permalink to &quot;行动的生命周期&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>过去心不可得，现在心不可得，未来心不可得。 《金刚经》</p></div><p>一条事项从「想到」到「做完留痕」，会依次落在不同<strong>问题域</strong>里；活动清单里的 <code>activity</code>、计划表里的 <code>todo</code> / <code>schedule</code>、任务追踪里的 <code>task</code> ，是为了让每一层只回答一类问题，避免把「库存、日历承诺、时钟占位、执行档案、专注回合」混在同一张表里。</p><ol><li><p><strong><code>activity</code>（活动清单）</strong><br> 回答：<strong>仓库里有什么？</strong><br> 事项仍处在收集、拆解、打标签、估番茄的阶段，<strong>尚未承诺</strong>落在计划表的哪一天；与具体执行日的绑定是可选的、可撤销的。</p></li><li><p><strong><code>todo</code> / <code>schedule</code>（计划表）</strong><br> 回答：<strong>我承诺在哪一天（及何种粒度上）处理它？</strong><br> 二者都来自活动清单中的条目，<code>schedule</code> 是与他人之间约定的事件，有跟多的“他律”，而 <code>todo</code> 可能有截止日期却其实并没有一个具体的人在事件中，更需要“自律”。</p></li><li><p><strong><code>task</code>（任务追踪）</strong><br> 回答：<strong>这一轮实际执行里发生了什么？</strong><br> 从灵感来源，发散的想法，到执行总结；能量、奖赏、打扰、书写模板等<strong>过程数据</strong>挂在追踪任务上；任何相关的信息。</p></li><li><p><strong>时间表与番茄时钟</strong><br> 时间表回答：<strong>今天 24 小时轴上，块落在哪一段？</strong><br> 番茄时钟回答：<strong>当前这一专注/休息回合的目标与节奏是什么？</strong><br> 利用标度时间经验来保护时间之流的经验，去理性的看到有限，在辅助中校准感受。它们辅助你，而不是替代你的感受。</p></li></ol><h2 id="「计划」与「意图」的区别" tabindex="-1">「计划」与「意图」的区别 <a class="header-anchor" href="#「计划」与「意图」的区别" aria-label="Permalink to &quot;「计划」与「意图」的区别&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>计划</strong>管日程与资源占位；<strong>意图</strong>管当下这一拍的启动与目标。</p></div><p>为避免与日常口语混用，在<strong>模块联动</strong>语境下建议这样读（与产品名中的 <em>Intention</em> 及 <a href="./../intro/what-is-pomotention.html">什么是 Pomotention？</a> 对齐）：</p><ul><li><p><strong>计划（plan）</strong><br> 指<strong>计划表 + 时间表</strong>所表达的安排：把活动放进具体日期、再在当日轴上挪动时段。回答的是 <strong>when（何时排进日程 / 轴上占位）</strong>。</p></li><li><p><strong>意图（intention）</strong><br> 在心理学语境指 <strong>执行意图</strong>（Implementation Intention）：把「打算做」写成易于触发行动的条件结构；在本应用中落实为 <strong>番茄意图</strong>——<strong>当前番茄（或休息）这一轮要瞄准什么</strong>，可与计划中的条目绑定，也可以先计时再补计划。回答的是 <strong>what / how to start（这一轮要达成什么、如何降低启动阻力）</strong>。</p></li></ul><h2 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>英文</th><th>中文</th><th>含义</th></tr></thead><tbody><tr><td>Activity</td><td>活动</td><td>活动清单里的一条记录，包括待办、预约、无所事事、内外打扰等。不是任务追踪里的「任务」。</td></tr><tr><td>Activity Sheet</td><td>活动清单</td><td>首页右侧用来收集、筛选和管理活动的区域。</td></tr><tr><td>Energy</td><td>精力值</td><td>任务追踪里记录的当下精力感受（1–10 分），时间轴上用 ⚡ 显示；仪表盘中的「平均精力值」也来自此类记录。</td></tr><tr><td>External Interruption</td><td>外部打扰</td><td>例如：来自他人来电、信息等的事项。</td></tr><tr><td>Internal Interruption</td><td>内部打扰</td><td>例如：来自个人情绪、想法和感受等的事项。</td></tr><tr><td>Planner</td><td>计划表</td><td>首页中上区域：按日/周/月查看，把待办、预约等排进具体日期，管理执行与完成状态。</td></tr><tr><td>Reward</td><td>奖赏值</td><td>任务追踪里记录的当下情绪与满意程度（1–10 分），时间轴上用 🏵️ 显示；仪表盘中的「平均奖赏值」也来自此类记录。</td></tr><tr><td>Schedule</td><td>预约</td><td>与他人约定具体时间、地点和时长的事项。</td></tr><tr><td>Task</td><td>任务</td><td>任务追踪里当前这一轮执行的记录：描述、精力、奖赏、打扰等都记在这里；通常从活动清单里某条活动点「追踪」后产生。与日常说的「任务」或 GTD 里的任务不是同一概念。</td></tr><tr><td>Task Tracker</td><td>任务追踪</td><td>首页中下区域：记录正在执行的任务，以及精力、奖赏、打扰与书写内容。</td></tr><tr><td>Timetable</td><td>时间表</td><td>首页左侧区域：在当天 24 小时轴上安排工作/休息等时间块，并把计划中的事项拖到时段里占位。</td></tr><tr><td>Todo</td><td>待办</td><td>用番茄块拆分的可执行项（🍅/🍒/🍇）。口语里的「待办任务」多指它，与任务追踪里的「任务」不是一回事。</td></tr><tr><td>Untaetigkeit</td><td>无所事事</td><td>与自己约定留白或发呆的时间段。</td></tr></tbody></table><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="./../reference/interface.html">软件界面</a>（各面板分区）</li><li><a href="./../reference/workflow.html">模块联动</a>（数据流与生命周期）</li><li><a href="./buttons.html">附录：按钮一览</a>（工具栏图标与英文标签速查）</li></ul>',13)]))}const u=r(a,[["render",n]]);export{p as __pageData,u as default};
